import{_ as t,o as a,c as o,a3 as n}from"./chunks/framework.BveOjhN0.js";const u=JSON.parse('{"title":"Authentication","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Authentication | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/developer-guide/authentication"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Authentication | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/developer-guide/authentication"}]]},"headers":[],"relativePath":"developer-guide/authentication.md","filePath":"developer-guide/authentication.md","lastUpdated":1784475221000}'),s={name:"developer-guide/authentication.md"};function i(r,e,d,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h1><p>Tenant and Central authentication are fully isolated: separate route trees, Sanctum guards, user models, password-reset brokers, and SPA token storage.</p><h2 id="architecture" tabindex="-1">Architecture <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;Architecture&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concern</th><th>Tenant Application</th><th>Central Application</th></tr></thead><tbody><tr><td>SPA routes</td><td><code>/login</code>, <code>/register</code>, <code>/forgot-password</code>, <code>/reset-password/{token}</code></td><td><code>/central/login</code>, <code>/central/forgot-password</code>, <code>/central/reset-password/{token}</code></td></tr><tr><td>API prefix</td><td><code>/api/tenant/v1</code></td><td><code>/api/central/v1</code></td></tr><tr><td>Guard</td><td><code>tenant-api</code></td><td><code>central-api</code></td></tr><tr><td>User model</td><td><code>App\\Models\\User</code> (<code>users</code>)</td><td><code>App\\Models\\CentralUser</code> (<code>central_users</code>)</td></tr><tr><td>Password broker</td><td><code>users</code></td><td><code>central_users</code></td></tr><tr><td>SPA token key</td><td><code>dc_saas_token_tenant</code></td><td><code>dc_saas_token_central</code></td></tr><tr><td>Token name</td><td><code>tenant-token</code></td><td><code>central-token</code></td></tr></tbody></table><p>A tenant login never authenticates a Central administrator, and a Central login never authenticates a tenant user.</p><p><code>/login</code> is the shared tenant entry point. It includes a <strong>Workspace</strong> field when the browser host does not already resolve a workspace; <code>/central/login</code> is always reserved for platform administrators and never accepts a workspace.</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flowchart LR</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  subgraph SPA</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    TAuth[&quot;/login /register /reset-password&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    CAuth[&quot;/central/login /central/reset-password&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    TDash[&quot;/dashboard widgets&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    CAdmin[&quot;/central/dashboard …&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  subgraph API</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    TAPI[&quot;tenant-api + User&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    CAPI[&quot;central-api + CentralUser&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    Reg[&quot;POST /public/register-workspace&quot;]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  end</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  TAuth --&gt; TAPI</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  CAuth --&gt; CAPI</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  TAuth --&gt;|register| Reg</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  Reg --&gt; TAPI</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  TAPI --&gt; TDash</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  CAPI --&gt; CAdmin</span></span></code></pre></div><h2 id="guards" tabindex="-1">Guards <a class="header-anchor" href="#guards" aria-label="Permalink to &quot;Guards&quot;">​</a></h2><p>Defined in <code>config/auth.php</code>:</p><ul><li><code>central-api</code> — Sanctum driver, <code>central_users</code> provider</li><li><code>tenant-api</code> — Sanctum driver, <code>users</code> provider</li></ul><p>Tenant routes also run <code>tenancy</code> + <code>tenant.available</code>. Workspace resolution prefers the request host (including future custom domains), then the authenticated token&#39;s workspace, then the submitted <code>workspace</code> value or <code>X-Tenant-Domain</code> header. Central routes run <code>central.domain</code>.</p><p>Spatie roles/permissions are isolated by <code>guard_name</code> (<code>central-api</code> vs <code>tenant-api</code>).</p><h2 id="registration" tabindex="-1">Registration <a class="header-anchor" href="#registration" aria-label="Permalink to &quot;Registration&quot;">​</a></h2><p><code>POST /api/central/v1/public/register-workspace</code> (honours <code>registration_enabled</code>):</p><ol><li>Creates workspace + domain</li><li><code>TenantProvisioningService</code> — billing profile, default-included modules (Leads, Tasks, Communication Templates), authorization defaults, module seed data</li><li><code>TenantAuthBootstrapService::createOwner</code> — owner <code>User</code> with workspace <code>superadmin</code> role (roles must already exist)</li><li>Returns Sanctum <code>tenant-token</code> for immediate SPA login</li></ol><p>Login and subsequent authenticated requests <strong>do not</strong> create or repair roles/permissions. See <a href="/developer-guide/tenant-provisioning">tenant-provisioning.md</a>.</p><p>Required body fields: <code>company_name</code>, <code>owner_name</code>, <code>email</code>, <code>password</code>, <code>password_confirmation</code>.</p><p>When registration is disabled, the API returns 403 with message <em>We are not currently accepting new registrations.</em> The SPA <code>/register</code> route redirects to <code>/registration-closed</code>.</p><h2 id="password-reset" tabindex="-1">Password reset <a class="header-anchor" href="#password-reset" aria-label="Permalink to &quot;Password reset&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Step</th><th>Tenant</th><th>Central</th></tr></thead><tbody><tr><td>Request</td><td><code>POST /api/tenant/v1/auth/forgot-password</code></td><td><code>POST /api/central/v1/auth/forgot-password</code></td></tr><tr><td>Email link</td><td><code>{FRONTEND_URL}/reset-password/{token}?email=</code></td><td><code>{FRONTEND_URL}/central/reset-password/{token}?email=</code></td></tr><tr><td>Reset</td><td><code>POST /api/tenant/v1/auth/reset-password</code></td><td><code>POST /api/central/v1/auth/reset-password</code></td></tr></tbody></table><p>Both reset endpoints use <code>App\\Rules\\PasswordRule</code>, which reads Central settings (<code>password_min_length</code>, <code>password_require_special</code>) plus always-on complexity rules.</p><p>Set <code>FRONTEND_URL</code> in the backend <code>.env</code> so reset/invite emails open the SPA.</p><h2 id="email-verification" tabindex="-1">Email verification <a class="header-anchor" href="#email-verification" aria-label="Permalink to &quot;Email verification&quot;">​</a></h2><p>Tenant <code>User</code> and Central users implement <code>MustVerifyEmail</code>. Verification is required before protected Central and tenant application APIs can be used. Routes:</p><ul><li><code>GET /api/tenant/v1/auth/email/verify/{id}/{hash}</code> (signed)</li><li><code>POST /api/tenant/v1/me/email/verification-notification</code> (self-service resend)</li><li><code>POST /api/tenant/v1/users/{user}/resend-verification</code> (<code>users.verify</code>; throttled <code>6,1</code>)</li><li><code>POST /api/tenant/v1/users/{user}/verify-email</code> (<code>users.verify</code>; manual mark verified)</li></ul><p>Admin verify/resend cannot target self or (for non-owners) the workspace owner. Manual verify and resend write platform audit events <code>tenant_user_email_verified</code> / <code>tenant_user_verification_resent</code>.</p><h2 id="impersonation-compatibility" tabindex="-1">Impersonation compatibility <a class="header-anchor" href="#impersonation-compatibility" aria-label="Permalink to &quot;Impersonation compatibility&quot;">​</a></h2><p>Login and registration issue tokens through <code>TenantAuthBootstrapService::issueAccessToken()</code> only — that service has <strong>no authorization side effects</strong>.<br><code>ImpersonationService</code> reuses the same token helper for Central → Tenant handoff when issuing a tenant token.</p><h2 id="token-↔-workspace-binding" tabindex="-1">Token ↔ workspace binding <a class="header-anchor" href="#token-↔-workspace-binding" aria-label="Permalink to &quot;Token ↔ workspace binding&quot;">​</a></h2><p>Sanctum tenant tokens are not intrinsically bound to a workspace. Authenticated tenant routes use middleware <code>tenant.user</code> (<code>EnsureTenantUserBelongsToCurrentTenant</code>) so a token issued for workspace A is rejected (401) when <code>X-Tenant-Domain</code> / host resolves to workspace B.</p><p><code>InitializeTenancy</code> re-resolves the tenant on every request and switches context when the domain/header changes (important for SPA clients that keep one API host and swap <code>X-Tenant-Domain</code>).</p><p>The SPA does not persist a workspace identifier in <code>localStorage</code>. It derives workspace context from the current host or the explicitly supplied login/request workspace, preventing stale browser state from selecting a different workspace.</p><h2 id="rate-limiting" tabindex="-1">Rate limiting <a class="header-anchor" href="#rate-limiting" aria-label="Permalink to &quot;Rate limiting&quot;">​</a></h2><ul><li>Login: <code>throttle:auth-login</code> (5/minute by email or IP)</li><li>Forgot/reset password: <code>throttle:6,1</code></li><li>Register workspace: <code>throttle:10,1</code></li></ul><h2 id="tenant-dashboard" tabindex="-1">Tenant dashboard <a class="header-anchor" href="#tenant-dashboard" aria-label="Permalink to &quot;Tenant dashboard&quot;">​</a></h2><p><code>GET /api/tenant/v1/dashboard</code> (auth + verified + subscription + <code>dashboard.view</code>) returns welcome copy, workspace info, installed modules, a <strong>widget registry</strong> (module + permission + assignee scoped), and overall <code>scope</code>. See <a href="/api/tenant-v1-dashboard">tenant-v1-dashboard.md</a>.</p>`,36)])])}const m=t(s,[["render",i]]);export{u as __pageData,m as default};
